import React, { useState, useEffect, useRef } from 'react';
import { Card, Tag, Button, Spin, Alert, Space, Tooltip, Typography } from 'antd';
import {
  VideoCameraOutlined,
  ReloadOutlined,
  PlayCircleOutlined,
  PauseCircleOutlined,
  EyeOutlined,
  SettingOutlined
} from '@ant-design/icons';
import { aiExperimenterApi } from '../services/api';

const { Text } = Typography;

interface CameraConfig {
  camera_id: string;
  name: string;
  channel: number;
  description: string;
}

interface CameraStatus {
  camera_id: string;
  name: string;
  channel: number;
  is_running: boolean;
  frame_count: number;
  runtime_seconds: number;
  last_frame_time?: number;
  last_error?: string;
  queue_size: number;
}

interface FrameData {
  camera_id: string;
  name: string;
  channel: number;
  timestamp: string;
  frame_data: string; // base64 encoded
  resolution: number[];
  frame_count: number;
  runtime_seconds: number;
}

interface RTSPVideoPlayerProps {
  camera: CameraConfig;
  autoRefresh?: boolean;
  refreshInterval?: number;
  style?: React.CSSProperties;
}

const RTSPVideoPlayer: React.FC<RTSPVideoPlayerProps> = ({
  camera,
  autoRefresh = true,
  refreshInterval = 1000, // 1秒
  style
}) => {
  const [isLoading, setIsLoading] = useState(false);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentFrame, setCurrentFrame] = useState<FrameData | null>(null);
  const [cameraStatus, setCameraStatus] = useState<CameraStatus | null>(null);
  const [error, setError] = useState<string | null>(null);
  const intervalRef = useRef<NodeJS.Timeout | null>(null);

  // 获取摄像头状态
  const fetchCameraStatus = async () => {
    try {
      const response = await aiExperimenterApi.getRTSPCameraStatus(camera.camera_id);
      if (response.success && response.camera_status) {
        setCameraStatus(response.camera_status);
        setIsPlaying(response.camera_status.is_running);
      }
    } catch (err) {
      console.error(`获取摄像头${camera.camera_id}状态失败:`, err);
    }
  };

  // 获取最新帧
  const fetchLatestFrame = async () => {
    try {
      const response = await aiExperimenterApi.getRTSPCameraFrame(camera.camera_id);
      if (response.success && response.data?.frame) {
        setCurrentFrame(response.data.frame);
        setError(null);
      } else {
        setError(response.error || '获取视频帧失败');
      }
    } catch (err) {
      setError('网络连接错误');
      console.error(`获取摄像头${camera.camera_id}帧失败:`, err);
    } finally {
      setIsLoading(false);
    }
  };

  // 启动摄像头
  const startCamera = async () => {
    setIsLoading(true);
    try {
      const response = await aiExperimenterApi.startRTSPCamera(camera.camera_id);
      if (response.success) {
        setIsPlaying(true);
        await fetchCameraStatus();
        // 等待摄像头启动后开始获取帧
        setTimeout(() => {
          fetchLatestFrame();
        }, 2000);
      } else {
        setError(response.error || '启动摄像头失败');
      }
    } catch (err) {
      setError('启动摄像头失败');
      console.error(`启动摄像头${camera.camera_id}失败:`, err);
    } finally {
      setIsLoading(false);
    }
  };

  // 停止摄像头
  const stopCamera = async () => {
    setIsLoading(true);
    try {
      const response = await aiExperimenterApi.stopRTSPCamera(camera.camera_id);
      if (response.success) {
        setIsPlaying(false);
        setCurrentFrame(null);
        await fetchCameraStatus();
      } else {
        setError(response.error || '停止摄像头失败');
      }
    } catch (err) {
      setError('停止摄像头失败');
      console.error(`停止摄像头${camera.camera_id}失败:`, err);
    } finally {
      setIsLoading(false);
    }
  };

  // 刷新当前帧
  const refreshFrame = async () => {
    if (isPlaying) {
      setIsLoading(true);
      await fetchLatestFrame();
    }
  };

  // 组件挂载时获取摄像头状态
  useEffect(() => {
    fetchCameraStatus();
  }, [camera.camera_id]);

  // 自动刷新设置
  useEffect(() => {
    if (autoRefresh && isPlaying) {
      intervalRef.current = setInterval(() => {
        fetchLatestFrame();
      }, refreshInterval);
    } else {
      if (intervalRef.current) {
        clearInterval(intervalRef.current);
        intervalRef.current = null;
      }
    }

    return () => {
      if (intervalRef.current) {
        clearInterval(intervalRef.current);
        intervalRef.current = null;
      }
    };
  }, [autoRefresh, isPlaying, refreshInterval, camera.camera_id]);

  // 获取状态标签
  const getStatusTag = () => {
    if (!cameraStatus) {
      return <Tag color="default">未知</Tag>;
    }

    if (error) {
      return <Tag color="red">错误</Tag>;
    }

    if (cameraStatus.is_running) {
      const lastUpdateAgo = cameraStatus.last_frame_time
        ? Date.now() / 1000 - cameraStatus.last_frame_time
        : Infinity;

      if (lastUpdateAgo > 5) {
        return <Tag color="orange">无信号</Tag>;
      }

      return <Tag color="green">实时</Tag>;
    }

    return <Tag color="default">已停止</Tag>;
  };

  // 获取状态文本
  const getStatusText = () => {
    if (!cameraStatus) return '状态未知';

    if (cameraStatus.is_running) {
      if (cameraStatus.frame_count > 0) {
        return `运行中 (${cameraStatus.frame_count}帧)`;
      }
      return '启动中...';
    }

    return '已停止';
  };

  // 格式化运行时间
  const formatRuntime = (seconds: number) => {
    const hours = Math.floor(seconds / 3600);
    const minutes = Math.floor((seconds % 3600) / 60);
    const secs = Math.floor(seconds % 60);

    if (hours > 0) {
      return `${hours}h ${minutes}m ${secs}s`;
    } else if (minutes > 0) {
      return `${minutes}m ${secs}s`;
    }
    return `${secs}s`;
  };

  return (
    <Card
      title={
        <Space>
          <VideoCameraOutlined />
          <span>{camera.name}</span>
          <Tooltip title={`通道 ${camera.channel}`}>
            <Text type="secondary" style={{ fontSize: '12px' }}>
              CH{camera.channel}
            </Text>
          </Tooltip>
        </Space>
      }
      size="small"
      extra={
        <Space>
          <Tooltip title={getStatusText()}>
            {getStatusTag()}
          </Tooltip>
          <Space size="small">
            {!isPlaying ? (
              <Tooltip title="启动摄像头">
                <Button
                  type="primary"
                  size="small"
                  icon={<PlayCircleOutlined />}
                  onClick={startCamera}
                  loading={isLoading}
                />
              </Tooltip>
            ) : (
              <Tooltip title="停止摄像头">
                <Button
                  danger
                  size="small"
                  icon={<PauseCircleOutlined />}
                  onClick={stopCamera}
                  loading={isLoading}
                />
              </Tooltip>
            )}
            {isPlaying && (
              <Tooltip title="刷新画面">
                <Button
                  size="small"
                  icon={<ReloadOutlined />}
                  onClick={refreshFrame}
                  loading={isLoading}
                />
              </Tooltip>
            )}
          </Space>
        </Space>
      }
      style={style}
    >
      {error && (
        <Alert
          message="摄像头错误"
          description={error}
          type="error"
          showIcon
          style={{ marginBottom: 8 }}
          action={
            <Button size="small" onClick={startCamera}>
              重试
            </Button>
          }
        />
      )}

      <div className="video-container" style={{ position: 'relative' }}>
        {/* 视频显示区域 */}
        <div
          style={{
            width: '100%',
            height: '200px',
            backgroundColor: '#000',
            borderRadius: '6px',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            position: 'relative',
            overflow: 'hidden'
          }}
        >
          {isLoading && !currentFrame && (
            <div style={{ position: 'absolute', zIndex: 2 }}>
              <Spin size="large" tip="连接中..." />
            </div>
          )}

          {currentFrame && currentFrame.frame_data ? (
            <img
              src={`data:image/jpeg;base64,${currentFrame.frame_data}`}
              alt={camera.name}
              style={{
                width: '100%',
                height: '100%',
                objectFit: 'cover',
                borderRadius: '6px'
              }}
              onError={() => {
                setError('图片加载失败');
              }}
            />
          ) : (
            !isLoading && (
              <div style={{
                color: '#666',
                textAlign: 'center',
                padding: '20px'
              }}>
                <VideoCameraOutlined style={{ fontSize: '48px', marginBottom: '8px' }} />
                <div>{isPlaying ? '等待视频信号...' : '摄像头未启动'}</div>
              </div>
            )
          )}

          {/* 实时标记 */}
          {isPlaying && currentFrame && (
            <div
              style={{
                position: 'absolute',
                top: '8px',
                right: '8px',
                backgroundColor: 'rgba(0, 0, 0, 0.6)',
                color: '#fff',
                padding: '2px 8px',
                borderRadius: '4px',
                fontSize: '12px',
                display: 'flex',
                alignItems: 'center',
                gap: '4px'
              }}
            >
              <div style={{
                width: '8px',
                height: '8px',
                backgroundColor: '#52c41a',
                borderRadius: '50%',
                animation: 'pulse 2s infinite'
              }} />
              LIVE
            </div>
          )}
        </div>

        {/* 信息栏 */}
        <div style={{
          marginTop: '8px',
          fontSize: '12px',
          color: '#666',
          display: 'flex',
          justifyContent: 'space-between'
        }}>
          <Space size="large">
            {currentFrame && (
              <span>
                分辨率: {currentFrame.resolution[0]}×{currentFrame.resolution[1]}
              </span>
            )}
            {cameraStatus && cameraStatus.is_running && (
              <span>
                运行: {formatRuntime(cameraStatus.runtime_seconds)}
              </span>
            )}
            {currentFrame && (
              <span>
                帧数: {currentFrame.frame_count}
              </span>
            )}
          </Space>

          {cameraStatus && (
            <span>
              队列: {cameraStatus.queue_size}
            </span>
          )}
        </div>
      </div>
    </Card>
  );
};

export default RTSPVideoPlayer;
